pub(super) fn normalize_ip_addr(addr: SocketAddrEx) -> SocketAddrEx {
    let SocketAddrEx::Ip(SocketAddr::V6(v6)) = addr else {
        return addr;
    };

    let ip = v6.ip();
    let octets = ip.octets();
    let mapped_v4 = (octets[..10] == [0; 10] && octets[10] == 0xff && octets[11] == 0xff)
        .then(|| Ipv4Addr::new(octets[12], octets[13], octets[14], octets[15]));
    let v4 = if ip.is_unspecified() {
        Ipv4Addr::UNSPECIFIED
    } else if ip.is_loopback() {
        Ipv4Addr::LOCALHOST
    } else if let Some(v4) = mapped_v4 {
        v4
    } else {
        return SocketAddrEx::Ip(SocketAddr::V6(v6));
    };

    SocketAddrEx::Ip(SocketAddr::V4(SocketAddrV4::new(v4, v6.port())))
}

pub fn sys_socket(domain: u32, raw_ty: u32, proto: u32) -> AxResult<isize> {
    debug!("sys_socket <= domain: {domain}, ty: {raw_ty}, proto: {proto}");
    let ty = raw_ty & 0xFF;
    if domain == AF_INET6 && ty == SOCK_RAW {
        if proto == 0 {
            return Err(AxError::from(LinuxError::EPROTONOSUPPORT));
        }
        let socket = RawIpv6Socket::new(proto);
        let cloexec = raw_ty & O_CLOEXEC != 0;
        return socket.add_to_fd_table(cloexec).map(|fd| fd as isize);
    }
    if domain == AF_PACKET && ty == SOCK_DGRAM {
        let socket = PacketSocket::new();
        let cloexec = raw_ty & O_CLOEXEC != 0;
        return socket.add_to_fd_table(cloexec).map(|fd| fd as isize);
    }

    let pid = current().as_thread().proc_data.proc.pid();
    let socket = match (domain, ty) {
        (AF_INET | AF_INET6, SOCK_STREAM) => {
            if proto != 0 && proto != IPPROTO_TCP as _ {
                return Err(AxError::from(LinuxError::EPROTONOSUPPORT));
            }
            SocketInner::Tcp(TcpSocket::new())
        }
        (AF_INET | AF_INET6, SOCK_DGRAM) => {
            if proto != 0 && proto != IPPROTO_UDP as _ {
                return Err(AxError::from(LinuxError::EPROTONOSUPPORT));
            }
            SocketInner::Udp(UdpSocket::new())
        }
        (AF_UNIX, SOCK_STREAM) => SocketInner::Unix(UnixSocket::new(StreamTransport::new(pid))),
        (AF_UNIX, SOCK_DGRAM) => SocketInner::Unix(UnixSocket::new(DgramTransport::new(pid))),
        #[cfg(feature = "vsock")]
        (AF_VSOCK, SOCK_STREAM) => {
            SocketInner::Vsock(VsockSocket::new(VsockStreamTransport::new()))
        }
        (AF_INET, _) | (AF_INET6, _) | (AF_UNIX, _) | (AF_VSOCK, _) => {
            warn!("Unsupported socket type: domain: {domain}, ty: {ty}");
            return Err(AxError::from(LinuxError::ESOCKTNOSUPPORT));
        }
        _ => {
            return Err(AxError::from(LinuxError::EAFNOSUPPORT));
        }
    };
    let socket = Socket(socket);

    if raw_ty & O_NONBLOCK != 0 {
        socket.set_nonblocking(true)?;
    }
    let cloexec = raw_ty & O_CLOEXEC != 0;

    socket.add_to_fd_table(cloexec).map(|fd| fd as isize)
}

pub fn sys_bind(fd: i32, addr: UserConstPtr<sockaddr>, addrlen: u32) -> AxResult<isize> {
    if let Ok(packet) = PacketSocket::from_fd(fd) {
        packet.bind_ll(addr, addrlen)?;
        return Ok(0);
    }

    let addr = normalize_ip_addr(SocketAddrEx::read_from_user(addr, addrlen)?);
    debug!("sys_bind <= fd: {fd}, addr: {addr:?}");

    if let SocketAddrEx::Ip(ip_addr) = &addr
        && ip_addr.port() < 1024
        && current().as_thread().proc_data.uid() != 0
    {
        return Err(AxError::from(LinuxError::EACCES));
    }

    if RawIpv6Socket::from_fd(fd).is_ok() {
        return Ok(0);
    }

    Socket::from_fd(fd)?.bind(addr)?;

    Ok(0)
}

pub fn sys_connect(fd: i32, addr: UserConstPtr<sockaddr>, addrlen: u32) -> AxResult<isize> {
    let addr = normalize_ip_addr(SocketAddrEx::read_from_user(addr, addrlen)?);
    debug!("sys_connect <= fd: {fd}, addr: {addr:?}");

    Socket::from_fd(fd)?.connect(addr).map_err(|e| {
        if e == AxError::WouldBlock {
            AxError::InProgress
        } else {
            e
        }
    })?;

    Ok(0)
}

pub fn sys_listen(fd: i32, backlog: i32) -> AxResult<isize> {
    debug!("sys_listen <= fd: {fd}, backlog: {backlog}");

    if backlog < 0 && backlog != -1 {
        return Err(AxError::InvalidInput);
    }

    Socket::from_fd(fd)?.listen()?;

    Ok(0)
}

pub fn sys_accept(
    fd: i32,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
) -> AxResult<isize> {
    sys_accept4(fd, addr, addrlen, 0)
}

pub fn sys_accept4(
    fd: i32,
    addr: UserPtr<sockaddr>,
    addrlen: UserPtr<socklen_t>,
    flags: u32,
) -> AxResult<isize> {
    debug!("sys_accept <= fd: {fd}, flags: {flags}");

    let cloexec = flags & O_CLOEXEC != 0;

    // Linux-like precedence for accept03:
    // - open_tree-style dummy/path fds => EBADF
    // - O_PATH file fds => EBADF
    // - ordinary non-socket fds => ENOTSOCK
    if let Ok(file_like) = get_file_like(fd) {
        if file_like.path().as_ref() == "anon_inode:[open_tree]" {
            return Err(AxError::BadFileDescriptor);
        }
    }
    if let Ok(file) = crate::file::File::from_fd(fd) {
        if file.flags() & linux_raw_sys::general::O_PATH as u32 != 0 {
            return Err(AxError::BadFileDescriptor);
        }
        return Err(AxError::NotASocket);
    }
    if crate::file::Directory::from_fd(fd).is_ok() {
        return Err(AxError::NotASocket);
    }

    let socket = Socket::from_fd(fd)?;
    let socket = Socket(socket.accept()?);
    if flags & O_NONBLOCK != 0 {
        socket.set_nonblocking(true)?;
    }

    let remote_addr = socket.local_addr()?;
    let fd = socket.add_to_fd_table(cloexec).map(|fd| fd as isize)?;
    debug!("sys_accept => fd: {fd}, addr: {remote_addr:?}");

    if !addr.is_null() {
        remote_addr.write_to_user(addr, addrlen.get_as_mut()?)?;
    }

    Ok(fd)
}

pub fn sys_shutdown(fd: i32, how: u32) -> AxResult<isize> {
    debug!("sys_shutdown <= fd: {fd}, how: {how:?}");

    let socket = Socket::from_fd(fd)?;
    let how = match how {
        SHUT_RD => Shutdown::Read,
        SHUT_WR => Shutdown::Write,
        SHUT_RDWR => Shutdown::Both,
        _ => return Err(AxError::InvalidInput),
    };
    socket.shutdown(how).map(|_| 0)
}

